Here's how to write modern MSTest tests for your `DataFetcher` class:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _fetcher;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _fetcher = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        _handler.ResponseContent = "hello world";
        _handler.StatusCode = HttpStatusCode.OK;

        // Act
        var result = await _fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        _handler.StatusCode = HttpStatusCode.InternalServerError;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _fetcher.FetchAsync(
                "https://example.com/data", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _fetcher.FetchAsync("https://example.com/data", cts.Token));
    }

    // Simple test double for HttpMessageHandler
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
        public string ResponseContent { get; set; } = string.Empty;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent),
            });
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| **Async tests** | `async Task` return type — MSTest awaits them natively |
| **Timeouts** | `[Timeout(5000)]` — auto-cancels via `TestContext.CancellationToken` |
| **CancellationToken** | Pass `_testContext.CancellationToken` so timeout cancellation propagates |
| **Cancellation testing** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Lifecycle** | Constructor injection of `TestContext`; `readonly` fields for test doubles |
| **Sealed class** | `sealed` for performance and design clarity |

The `[Timeout]` + `TestContext.CancellationToken` combination is critical — if your test hangs (e.g., a real HTTP call accidentally leaks through), the timeout fires and the cancellation token aborts the async operation cleanly rather than leaving the test stuck.
